<?phpnamespace app\Models;require_once("Database.php");use app\Database;use PDO;abstract class Product{    protected $info;    function __construct($info)    {        $this->info = $info;    }    public function getInfo()    {        return $this->info;    }    static function validateInfo($info)    {        $errors = self::isFilled($info);        if ($errors)        {            $errors["empty"] = "Please, submit required data";        }        if (!isset($errors["sku"]) && !self::isSKUValid($info["sku"]))        {            $errors["sku"] = "SKU must be unique";        }        if (!isset($errors["price"]) && !self::isPriceValid($info["price"]))        {            $errors["price"] = "Please, provide the data of indicated type";        }        return $errors;    }    private static function isSKUValid($sku)    {        $db = new Database();        $sql = $db->getSKU();        while ($row = $sql->fetch(PDO::FETCH_ASSOC))        {            if ($row["sku"] == $sku)            {                return false;            }        }        return true;    }    private static function isPriceValid($price)    {        if (!is_numeric($price) || $price < 0)        {            return false;        }        return true;    }    static function isFilled($info)    {        $fields = array_keys($info);        $errors = [];        foreach ($fields as $field)        {            if (strlen($info[$field]) == 0)            {                $errors[$field] = "Please enter " . $field;            }        }        return $errors;    }}